sys_script_email.script:
(function runMailScript(current, template, email, email_action, event) {

    template.print('<table border="1" cellpadding="5" cellspacing="0">');

    template.print('<tr><td><b>Number</b></td><td>' + current.number + '</td></tr>');

    template.print('<tr><td><b>State</b></td><td>' + current.state + '</td></tr>');

    template.print('<tr><td><b>Short Description</b></td><td>' + current.short_description + '</td></tr>');

    template.print('<tr><td><b>Product</b></td><td>' + current.product.getDisplayValue() + '</td></tr>');

    template.print('<tr><td><b>Assignment Group</b></td><td>' + current.assignment_group.getDisplayValue() + '</td></tr>');

    template.print('<tr><td><b>Assigned To</b></td><td>' + current.assigned_to.getDisplayValue() + '</td></tr>');


    template.print('</table>');

})(current, template, email, email_action, event);
